const input = $input.first().json;
const action = input.action || 'search_repos';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.github-api&cred_key=eq.github_pat&select=cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0 || !creds[0].cred_value) {
  return [{ json: { error: 'GitHub PAT not configured. Use add_credential to set it up.' } }];
}

const token = creds[0].cred_value;
const ghHeaders = {
  'Authorization': 'Bearer ' + token,
  'Accept': 'application/vnd.github+json',
  'X-GitHub-Api-Version': '2022-11-28'
};

function formatNumber(n) {
  if (n >= 1000) return (n / 1000).toFixed(1) + 'k';
  return String(n);
}

if (action === 'search_repos') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required.' } }];
  const sort = input.sort || 'stars';

  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: 'https://api.github.com/search/repositories?q=' + encodeURIComponent(query) + '&sort=' + sort + '&per_page=5',
      headers: ghHeaders
    });

    if (!data.items || data.items.length === 0) {
      return [{ json: { error: 'No repositories found for "' + query + '".' } }];
    }

    let result = 'GitHub repos for "' + query + '" (' + data.total_count + ' total):\n\n';
    for (const r of data.items) {
      result += '**' + r.full_name + '**';
      result += ' — ' + formatNumber(r.stargazers_count) + ' stars, ' + formatNumber(r.forks_count) + ' forks\n';
      if (r.description) result += r.description.substring(0, 150) + '\n';
      if (r.language) result += 'Language: ' + r.language + '\n';
      result += r.html_url + '\n\n';
    }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'GitHub search failed: ' + err.message } }];
  }

} else if (action === 'get_repo_info') {
  const owner = input.owner;
  const repo = input.repo;
  if (!owner || !repo) return [{ json: { error: 'Parameters "owner" and "repo" are required.' } }];

  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: 'https://api.github.com/repos/' + encodeURIComponent(owner) + '/' + encodeURIComponent(repo),
      headers: ghHeaders
    });

    let result = '**' + data.full_name + '**\n';
    if (data.description) result += data.description + '\n';
    result += '\n';
    result += 'Stars: ' + formatNumber(data.stargazers_count) + '\n';
    result += 'Forks: ' + formatNumber(data.forks_count) + '\n';
    result += 'Open Issues: ' + data.open_issues_count + '\n';
    if (data.language) result += 'Language: ' + data.language + '\n';
    if (data.license && data.license.spdx_id) result += 'License: ' + data.license.spdx_id + '\n';
    result += 'Created: ' + data.created_at.split('T')[0] + '\n';
    result += 'Last Push: ' + data.pushed_at.split('T')[0] + '\n';
    if (data.topics && data.topics.length > 0) result += 'Topics: ' + data.topics.join(', ') + '\n';
    result += 'URL: ' + data.html_url + '\n';

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get repo info: ' + err.message } }];
  }

} else if (action === 'list_issues') {
  const owner = input.owner;
  const repo = input.repo;
  if (!owner || !repo) return [{ json: { error: 'Parameters "owner" and "repo" are required.' } }];
  const state = input.state || 'open';

  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: 'https://api.github.com/repos/' + encodeURIComponent(owner) + '/' + encodeURIComponent(repo) + '/issues?state=' + state + '&per_page=10',
      headers: ghHeaders
    });

    if (!data || data.length === 0) {
      return [{ json: { result: 'No ' + state + ' issues found in ' + owner + '/' + repo + '.' } }];
    }

    // Filter out PRs (GitHub API returns PRs as issues too)
    const issues = data.filter(i => !i.pull_request);

    if (issues.length === 0) {
      return [{ json: { result: 'No ' + state + ' issues found in ' + owner + '/' + repo + ' (only pull requests).' } }];
    }

    let result = state.charAt(0).toUpperCase() + state.slice(1) + ' issues in ' + owner + '/' + repo + ':\n\n';
    for (const i of issues) {
      result += '#' + i.number + ' — **' + i.title + '**\n';
      if (i.labels && i.labels.length > 0) result += '  Labels: ' + i.labels.map(l => l.name).join(', ') + '\n';
      result += '  Created: ' + i.created_at.split('T')[0];
      if (i.assignee) result += ' | Assignee: ' + i.assignee.login;
      result += '\n\n';
    }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list issues: ' + err.message } }];
  }

} else if (action === 'create_issue') {
  const owner = input.owner;
  const repo = input.repo;
  const title = input.title;
  if (!owner || !repo || !title) return [{ json: { error: 'Parameters "owner", "repo", and "title" are required.' } }];

  try {
    const body = { title };
    if (input.body) body.body = input.body;
    if (input.labels) body.labels = input.labels.split(',').map(l => l.trim());

    const data = await helpers.httpRequest({
      method: 'POST',
      url: 'https://api.github.com/repos/' + encodeURIComponent(owner) + '/' + encodeURIComponent(repo) + '/issues',
      headers: { ...ghHeaders, 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });

    return [{ json: { result: 'Issue created: #' + data.number + ' — ' + data.title + '\n' + data.html_url } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create issue: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use search_repos, get_repo_info, list_issues, or create_issue.' } }];
}
